Here's what the file would look like with these improvements applied:

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security Middleware ---
app.use(helmet());

app.use(express.json({ limit: '10kb' }));  // Limit body size to prevent DoS
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting: max 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Disable X-Powered-By (also done by helmet, but explicit is good)
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate query params if accepting user input (e.g., pagination)
  const page = parseInt(req.query.page, 10);
  const limit = parseInt(req.query.limit, 10);

  if (req.query.page !== undefined && (isNaN(page) || page < 1)) {
    return res.status(400).json({ error: 'Invalid page parameter' });
  }
  if (req.query.limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
    return res.status(400).json({ error: 'Invalid limit parameter (1-100)' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler (must have 4 params) ---
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err.message);
  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Server ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

