app.get('/users',
  query('id').optional().isInt({ min: 1 }).toInt(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... handle request
  }
);
```

### 9. **No Graceful Shutdown**
The server doesn't handle `SIGTERM`/`SIGINT`, which can cause dropped connections during deploys:

```js
const server = app.listen(PORT, () => { ... });

process.on('SIGTERM', () => {
  server.close(() => {
    console.log('Server shut down gracefully');
    process.exit(0);
  });
});
```

